"ad_by_channel_group":"SELECT channel_id, group_id, SUM(leads_generated) leads, SUM(spend) spend FROM ad_channel_leads GROUP BY channel_id, group_id ORDER BY leads DESC",
"ledger_by_cat":"SELECT category, SUM(amount) amount, COUNT(*) n FROM ledger GROUP BY category ORDER BY amount",
"subs":"SELECT s.plan, c.group_id, COUNT(*) n, AVG(s.effective_price) avg_price, SUM(s.seat_count) seats FROM subscriptions s JOIN customers c USING(customer_id) WHERE s.status='active' GROUP BY s.plan, c.group_id",
"customers_by_group":"SELECT group_id, acquisition_source, customer_type, COUNT(*) n FROM customers GROUP BY group_id, acquisition_source, customer_type ORDER BY n DESC LIMIT 50",
"enterprise_pending":"SELECT * FROM enterprise_turns WHERE closed=0 ORDER BY day, message_id LIMIT 50"
}
for name,q in queries.items():
    print("--", name)
    try: print(json.dumps(nm.query(q), indent=2))
