results={}
try:
    results["research_t7"]=nm.research.start_research_project(tier=7)
except Exception as e:
    results["research_t7"]={"error": str(e)}
for gid in ["D_E08","D_E02","D_E09","E3"]:
    try:
        results[f"research_{gid}"]=nm.market.research_group(group_id=gid)
    except Exception as e:
        results[f"research_{gid}"]={"error": str(e)}
results["prices"]=nm.pricing.set_prices(A=109,B=279,C=499)
results["tiers"]=nm.pricing.set_model_tiers(A=3,B=3,C=5)
results["quotas"]=nm.pricing.set_usage_quotas(A=40000,B=160000,C=400000)
results["capacity"]=nm.infrastructure.set_capacity_tier(tier=6)
results["daily_spend"]=nm.marketing.set_daily_spend(operations=25000, development=200)
results["targeted_dev"]=nm.analytics.set_targeted_dev_spend(targeted_spend={"S2":2000,"S3":1000,"D_E08":5000,"D_E02":3000,"D_E09":3000,"E3":5000})
results["targeted_ops"]=nm.analytics.set_targeted_ops_spend(targeted_spend={"S2":75000,"S3":1000,"D_E08":5000,"D_E02":5000,"D_E09":3000,"E3":5000})
results["lead_promo"]=nm.marketing.set_lead_promotion(by_group={"S2":0,"S3":30,"S1":15})
results["ads"]=nm.marketing.set_targeted_ad_spend(targeted_spend={"content_marketing":{"S2":40000},"linkedin":{"D_E08":20000,"D_E02":15000,"D_E09":10000,"E3":10000}})
print(json.dumps(results, indent=2, default=str))'

