q="""WITH latest AS (SELECT customer_id, MAX(message_id) max_mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id) SELECT et.customer_id, c.group_id, et.seat_count FROM enterprise_turns et JOIN latest l ON et.customer_id=l.customer_id AND et.message_id=l.max_mid JOIN customers c ON c.customer_id=et.customer_id WHERE et.closed=0 AND et.sender='system' ORDER BY c.group_id, et.customer_id"""
rows=nm.query(q)["rows"]
deals=[]
counts={}
for r in rows:
    gid=r["group_id"]; cid=r["customer_id"]
    counts[gid]=counts.get(gid,0)+1
    if gid=="D_E02":
        offers=[["A",69.0],["B",89.0],["C",129.0]]
