arguments.cmd:
./novamind-operation python-c $'import novamind_api as nm, json
q="""SELECT DISTINCT et.customer_id, c.group_id FROM enterprise_turns et JOIN customers c ON c.customer_id=et.customer_id WHERE et.closed=0 ORDER BY c.group_id, et.customer_id"""
rows=nm.query(q)["rows"]
deals=[]
counts={}
for r in rows:
    gid=r["group_id"]; cid=r["customer_id"]
    counts[gid]=counts.get(gid,0)+1
    if gid=="D_E02":
        offers=[["A",59.0],["B",69.0],["C",99.0]]
    elif gid=="D_E08":
        offers=[["A",119.0],["B",139.0],["C",169.0]]
    elif gid=="D_E09":
        offers=[["A",79.0],["B",99.0],["C",129.0]]
    elif gid=="E3":
        offers=[["A",89.0],["B",99.0],["C",119.0]]
    else:
        offers=[["A",69.0],["B",89.0],["C",129.0]]
    deals.append([cid, offers])
res=nm.enterprise.send_enterprise_deal(deals=deals)
success=sum(1 for x in res.get("results",[]) if x.get("success"))
fail=[x for x in res.get("results",[]) if not x.get("success")]
print(json.dumps({"counts":counts,"sent":len(deals),"success":success,"failures":fail[:10],"failure_count":len(fail)}, indent=2, default=str))'

